import { useState } from "react";
import { useTranslation } from "react-i18next";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Textarea } from "@/components/ui/textarea";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Skeleton } from "@/components/ui/skeleton";
import { toast } from "sonner";
import { CheckCircle, XCircle, Clock, Eye, Globe, MapPin, ExternalLink, Megaphone, Trash2 } from "lucide-react";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle } from "@/components/ui/alert-dialog";
import { format } from "date-fns";

const AdminAdRequests = () => {
  const { t } = useTranslation();
  const { user } = useAuth();
  const queryClient = useQueryClient();
  const [selectedRequest, setSelectedRequest] = useState<any>(null);
  const [adminNotes, setAdminNotes] = useState("");
  const [reviewAction, setReviewAction] = useState<"approve" | "reject" | null>(null);
  const [deleteTarget, setDeleteTarget] = useState<any>(null);

  const { data: requests = [], isLoading } = useQuery({
    queryKey: ["admin-ad-requests"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("ad_requests" as any)
        .select("*")
        .order("created_at", { ascending: false });
      if (error) throw error;

      const userIds = [...new Set((data as any[]).map((r: any) => r.user_id))];
      const { data: profiles } = await supabase
        .from("profiles")
        .select("id, display_name, avatar_url")
        .in("id", userIds);

      const profileMap = new Map((profiles || []).map(p => [p.id, p]));
      return (data as any[]).map((r: any) => ({
        ...r,
        requester: profileMap.get(r.user_id) || null,
      }));
    },
  });

  const reviewMutation = useMutation({
    mutationFn: async ({ id, status, notes }: { id: string; status: string; notes: string }) => {
      const updateData: any = {
        status,
        admin_notes: notes || null,
        reviewed_by: user?.id,
        reviewed_at: new Date().toISOString(),
      };

      if (status === "approved") {
        const request = requests.find((r: any) => r.id === id);
        if (request) {
          const { data: newAd, error: adError } = await supabase
            .from("store_ads")
            .insert({
              name: request.ad_name,
              image_url: request.image_url,
              link_url: request.link_url,
              global_enabled: request.global_enabled,
              target_countries: request.target_countries || [],
              is_active: true,
              start_date: request.desired_start_date || new Date().toISOString().split("T")[0],
              end_date: request.desired_start_date && request.desired_duration_months
                ? new Date(new Date(request.desired_start_date).setMonth(
                    new Date(request.desired_start_date).getMonth() + request.desired_duration_months
                  )).toISOString().split("T")[0]
                : null,
            })
            .select("id")
            .single();
          if (adError) throw adError;
          updateData.created_ad_id = newAd.id;
        }
      }

      const { error } = await supabase
        .from("ad_requests" as any)
        .update(updateData)
        .eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["admin-ad-requests"] });
      toast.success(t("admin.adRequests.reviewSuccess"));
      setSelectedRequest(null);
      setReviewAction(null);
      setAdminNotes("");
    },
    onError: (err: any) => {
      toast.error(err.message || t("admin.adRequests.operationFailed"));
    },
  });

  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase
        .from("ad_requests" as any)
        .delete()
        .eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["admin-ad-requests"] });
      toast.success(t("admin.adRequests.deleteSuccess"));
      setDeleteTarget(null);
    },
    onError: (err: any) => {
      toast.error(err.message || t("admin.adRequests.deleteFailed"));
    },
  });

  const getStatusBadge = (status: string) => {
    switch (status) {
      case "pending":
        return <Badge variant="secondary" className="gap-1"><Clock className="h-3 w-3" />{t("admin.adRequests.statusPending")}</Badge>;
      case "approved":
        return <Badge className="gap-1 bg-primary"><CheckCircle className="h-3 w-3" />{t("admin.adRequests.statusApproved")}</Badge>;
      case "rejected":
        return <Badge variant="destructive" className="gap-1"><XCircle className="h-3 w-3" />{t("admin.adRequests.statusRejected")}</Badge>;
      default:
        return <Badge variant="outline">{status}</Badge>;
    }
  };

  const pendingCount = requests.filter((r: any) => r.status === "pending").length;

  if (isLoading) {
    return (
      <div className="space-y-4 p-6">
        <Skeleton className="h-8 w-48" />
        <Skeleton className="h-64 w-full" />
      </div>
    );
  }

  return (
    <div className="space-y-6 p-6">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <Megaphone className="h-6 w-6 text-primary" />
          <h1 className="text-xl font-bold">{t("admin.adRequests.title")}</h1>
          {pendingCount > 0 && (
            <Badge variant="destructive">{pendingCount} {t("admin.adRequests.pending")}</Badge>
          )}
        </div>
      </div>

      <Card>
        <CardContent className="p-0">
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>{t("admin.adRequests.applicant")}</TableHead>
                <TableHead>{t("admin.adRequests.adName")}</TableHead>
                <TableHead>{t("admin.adRequests.preview")}</TableHead>
                <TableHead>{t("admin.adRequests.scope")}</TableHead>
                <TableHead>{t("admin.adRequests.duration")}</TableHead>
                <TableHead>{t("admin.adRequests.status")}</TableHead>
                <TableHead>{t("admin.adRequests.time")}</TableHead>
                <TableHead>{t("admin.adRequests.actions")}</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {requests.length === 0 ? (
                <TableRow>
                  <TableCell colSpan={8} className="text-center py-8 text-muted-foreground">
                    {t("admin.adRequests.empty")}
                  </TableCell>
                </TableRow>
              ) : (
                requests.map((req: any) => (
                  <TableRow key={req.id}>
                    <TableCell>
                      <span className="text-sm font-medium">
                        {req.requester?.display_name || t("admin.adRequests.unknownUser")}
                      </span>
                    </TableCell>
                    <TableCell className="font-medium max-w-[150px] truncate">
                      {req.ad_name}
                    </TableCell>
                    <TableCell>
                      {req.image_url && (
                        <img
                          src={req.image_url}
                          alt={req.ad_name}
                          className="w-20 h-12 object-cover rounded border border-border"
                        />
                      )}
                    </TableCell>
                    <TableCell>
                      {req.global_enabled ? (
                        <span className="flex items-center gap-1 text-xs"><Globe className="h-3 w-3" />{t("admin.adRequests.global")}</span>
                      ) : (
                        <span className="flex items-center gap-1 text-xs">
                          <MapPin className="h-3 w-3" />
                          {(req.target_countries || []).join(", ") || t("admin.adRequests.notSpecified")}
                        </span>
                      )}
                    </TableCell>
                    <TableCell className="text-sm">
                      {req.desired_duration_months ? t("admin.adRequests.months", { count: req.desired_duration_months }) : "-"}
                    </TableCell>
                    <TableCell>{getStatusBadge(req.status)}</TableCell>
                    <TableCell className="text-xs text-muted-foreground">
                      {format(new Date(req.created_at), "yyyy-MM-dd HH:mm")}
                    </TableCell>
                    <TableCell>
                      <div className="flex items-center gap-1">
                        <Button
                          variant="outline"
                          size="sm"
                          onClick={() => {
                            setSelectedRequest(req);
                            setAdminNotes(req.admin_notes || "");
                          }}
                        >
                          <Eye className="h-3 w-3 mr-1" />
                          {t("admin.adRequests.view")}
                        </Button>
                        <Button
                          variant="ghost"
                          size="sm"
                          className="text-destructive hover:text-destructive"
                          onClick={() => setDeleteTarget(req)}
                        >
                          <Trash2 className="h-3 w-3" />
                        </Button>
                      </div>
                    </TableCell>
                  </TableRow>
                ))
              )}
            </TableBody>
          </Table>
        </CardContent>
      </Card>

      {/* Detail / Review Dialog */}
      <Dialog open={!!selectedRequest} onOpenChange={() => { setSelectedRequest(null); setReviewAction(null); }}>
        <DialogContent className="max-w-lg">
          <DialogHeader>
            <DialogTitle>{t("admin.adRequests.detail")}</DialogTitle>
          </DialogHeader>
          {selectedRequest && (
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-3 text-sm">
                <div>
                  <span className="text-muted-foreground">{t("admin.adRequests.applicant")}:</span>
                  <p className="font-medium">{selectedRequest.requester?.display_name || t("admin.adRequests.unknownUser")}</p>
                </div>
                <div>
                  <span className="text-muted-foreground">{t("admin.adRequests.adName")}:</span>
                  <p className="font-medium">{selectedRequest.ad_name}</p>
                </div>
                <div>
                  <span className="text-muted-foreground">{t("admin.adRequests.scope")}:</span>
                  <p>{selectedRequest.global_enabled ? t("admin.adRequests.global") : (selectedRequest.target_countries || []).join(", ") || t("admin.adRequests.notSpecified")}</p>
                </div>
                <div>
                  <span className="text-muted-foreground">{t("admin.adRequests.duration")}:</span>
                  <p>{selectedRequest.desired_duration_months ? t("admin.adRequests.months", { count: selectedRequest.desired_duration_months }) : t("admin.adRequests.notSpecified")}</p>
                </div>
                {selectedRequest.desired_start_date && (
                  <div>
                    <span className="text-muted-foreground">{t("admin.adRequests.desiredStart")}:</span>
                    <p>{selectedRequest.desired_start_date}</p>
                  </div>
                )}
                {selectedRequest.link_url && (
                  <div className="col-span-2">
                    <span className="text-muted-foreground">{t("admin.adRequests.link")}:</span>
                    <p className="flex items-center gap-1 break-all">
                      <ExternalLink className="h-3 w-3 shrink-0" />
                      {selectedRequest.link_url}
                    </p>
                  </div>
                )}
                {selectedRequest.description && (
                  <div className="col-span-2">
                    <span className="text-muted-foreground">{t("admin.adRequests.description")}:</span>
                    <p className="mt-1">{selectedRequest.description}</p>
                  </div>
                )}
              </div>

              {selectedRequest.image_url && (
                <img
                  src={selectedRequest.image_url}
                  alt="Ad preview"
                  className="w-full h-48 object-cover rounded-lg border border-border"
                />
              )}

              {selectedRequest.notes && (
                <div className="text-sm">
                  <span className="text-muted-foreground">{t("admin.adRequests.merchantNotes")}:</span>
                  <p className="mt-1 p-2 bg-muted rounded text-sm">{selectedRequest.notes}</p>
                </div>
              )}

              {selectedRequest.status === "pending" && (
                <div className="space-y-3 pt-2">
                  <Textarea
                    value={adminNotes}
                    onChange={e => setAdminNotes(e.target.value)}
                    placeholder={t("admin.adRequests.adminNotesPlaceholder")}
                    rows={3}
                  />
                  <div className="flex gap-2">
                    <Button
                      className="flex-1"
                      onClick={() => reviewMutation.mutate({
                        id: selectedRequest.id,
                        status: "approved",
                        notes: adminNotes,
                      })}
                      disabled={reviewMutation.isPending}
                    >
                      <CheckCircle className="h-4 w-4 mr-1" />
                      {t("admin.adRequests.approveAndCreate")}
                    </Button>
                    <Button
                      variant="destructive"
                      className="flex-1"
                      onClick={() => reviewMutation.mutate({
                        id: selectedRequest.id,
                        status: "rejected",
                        notes: adminNotes,
                      })}
                      disabled={reviewMutation.isPending}
                    >
                      <XCircle className="h-4 w-4 mr-1" />
                      {t("admin.adRequests.reject")}
                    </Button>
                  </div>
                </div>
              )}

              {selectedRequest.status !== "pending" && (
                <div className="text-sm space-y-1">
                  <div className="flex items-center gap-2">
                    <span className="text-muted-foreground">{t("admin.adRequests.reviewStatus")}:</span>
                    {getStatusBadge(selectedRequest.status)}
                  </div>
                  {selectedRequest.admin_notes && (
                    <div>
                      <span className="text-muted-foreground">{t("admin.adRequests.adminNotes")}:</span>
                      <p className="mt-1 p-2 bg-muted rounded">{selectedRequest.admin_notes}</p>
                    </div>
                  )}
                  {selectedRequest.reviewed_at && (
                    <p className="text-muted-foreground text-xs">
                      {t("admin.adRequests.reviewTime")}: {format(new Date(selectedRequest.reviewed_at), "yyyy-MM-dd HH:mm")}
                    </p>
                  )}
                </div>
              )}
            </div>
          )}
        </DialogContent>
      </Dialog>

      {/* Delete Confirmation */}
      <AlertDialog open={!!deleteTarget} onOpenChange={() => setDeleteTarget(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>{t("admin.adRequests.deleteTitle")}</AlertDialogTitle>
            <AlertDialogDescription>
              {t("admin.adRequests.deleteDesc", { name: deleteTarget?.ad_name })}
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>{t("admin.adRequests.cancel")}</AlertDialogCancel>
            <AlertDialogAction
              onClick={() => deleteTarget && deleteMutation.mutate(deleteTarget.id)}
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
            >
              {t("admin.adRequests.delete")}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
};

export default AdminAdRequests;
